-- =============================================================================
-- Dino Arm Tourney — Production schema baseline (2026-04-30)
-- =============================================================================
-- Source of truth for a fresh Postgres / Supabase database.
-- Generated by introspecting the dev project (hmvnelyzqqdfidjalsha) on
-- 2026-04-30 to realign prod (nmglfsqwlhacdcqqmday) which had drifted.
--
-- Apply order on a clean public schema:
--   1. supabase/schema.sql   (this file)
--   2. supabase/seed.sql     (rule_profiles reference data)
--
-- Wipe-and-restore recipe (Supabase Studio → SQL Editor on prod):
--   drop schema public cascade;
--   create schema public;
--   grant all  on schema public to postgres, service_role;
--   grant usage on schema public to anon, authenticated;
--   -- then paste THIS file, then seed.sql.
--
-- Auth users (auth.*) and storage objects (storage.*) are NOT touched.
-- =============================================================================

-- -----------------------------------------------------------------------------
-- Extensions
-- -----------------------------------------------------------------------------
create extension if not exists "pgcrypto";
create extension if not exists "uuid-ossp";

-- -----------------------------------------------------------------------------
-- Sequences (explicit, non-serial)
-- -----------------------------------------------------------------------------
create sequence if not exists public.audit_log_id_seq as bigint start 1;

-- =============================================================================
-- TABLES (columns + defaults + NOT NULL only; constraints added below)
-- =============================================================================

-- profiles --------------------------------------------------------------------
create table if not exists public.profiles (
    id                uuid not null,
    full_name         text,
    phone             text,
    role              text not null default 'athlete',
    created_at        timestamptz not null default now(),
    email             text,
    invited_by        uuid,
    invited_at        timestamptz,
    disabled_at       timestamptz,
    last_seen_at      timestamptz,
    erase_started_at  timestamptz
);

-- organizations ---------------------------------------------------------------
create table if not exists public.organizations (
    id          uuid not null default gen_random_uuid(),
    slug        text not null,
    name        text not null,
    kind        text not null,
    country     text not null default 'IN',
    region      text,
    created_at  timestamptz not null default now()
);

-- rule_profiles ---------------------------------------------------------------
create table if not exists public.rule_profiles (
    id                uuid not null default gen_random_uuid(),
    code              text not null,
    name              text not null,
    bracket_default   text not null default 'double_elim',
    protest_fee_inr   integer default 500,
    warnings_per_foul integer default 2,
    fouls_to_lose     integer default 2,
    weight_classes    jsonb not null default '[]'::jsonb,
    created_at        timestamptz not null default now()
);

-- events ----------------------------------------------------------------------
create table if not exists public.events (
    id                          uuid not null default gen_random_uuid(),
    organization_id             uuid not null,
    rule_profile_id             uuid,
    slug                        text not null,
    name                        text not null,
    status                      text not null default 'draft',
    starts_at                   timestamptz not null,
    ends_at                     timestamptz,
    venue_name                  text,
    venue_city                  text,
    venue_state                 text,
    cover_url                   text,
    description                 text,
    entry_fee_inr               integer default 0,
    currency                    text not null default 'INR',
    prize_pool_inr              bigint default 0,
    registration_opens_at       timestamptz,
    registration_closes_at      timestamptz,
    weigh_in_starts_at          timestamptz,
    weigh_in_ends_at            timestamptz,
    hand                        text not null default 'right',
    created_by                  uuid,
    created_at                  timestamptz not null default now(),
    registration_published_at   timestamptz,
    registration_closed_at      timestamptz,
    payment_provider            text not null default 'manual_upi',
    upi_id                      text,
    upi_payee_name              text,
    entry_fee_default_inr       integer default 500,
    fee_overrides               jsonb default '{}'::jsonb,
    logo_url                    text,
    banner_url                  text,
    primary_color               text default '#0f3d2e',
    accent_color                text default '#f5c518',
    text_on_primary             text default '#ffffff',
    id_card_template            text default 'tnawa_v1',
    id_card_org_name            text,
    id_card_event_title         text,
    id_card_subtitle            text,
    id_card_footer              text,
    id_card_signatory_name      text,
    id_card_signatory_title     text,
    id_card_signature_url       text,
    poster_url                  text,
    poster_kind                 text,
    circular_url                text,
    payment_mode                text not null default 'online_upi',
    id_card_org_name_size       smallint,
    id_card_event_title_size    smallint,
    bracket_format              text not null default 'double_elim',
    entry_fee_offline_inr       integer,
    entry_fee_para_inr          integer,
    -- Per-event Challonge integration (migration 0045). When enabled,
    -- /admin/events/:id/categories pushes one Challonge tournament per
    -- category under the configured Premier subdomain. The api_key is
    -- write-only from the UI and never returned to the client.
    challonge_enabled           boolean not null default false,
    challonge_api_key           text,
    challonge_username          text,
    challonge_subdomain         text
);

-- athletes --------------------------------------------------------------------
create table if not exists public.athletes (
    id              uuid not null,
    date_of_birth   date,
    gender          text,
    state           text,
    district        text,
    pan_masked      text,
    aadhaar_masked  text,
    created_at      timestamptz not null default now(),
    is_para         boolean not null default false,
    para_class      text,
    para_posture    text,
    aadhaar         text
);

-- registrations ---------------------------------------------------------------
create table if not exists public.registrations (
    id                  uuid not null default gen_random_uuid(),
    event_id            uuid not null,
    athlete_id          uuid,
    weight_class_code   text,
    hand                text not null default 'right',
    status              text not null default 'pending',
    paid_amount_inr     integer default 0,
    payment_ref         text,
    created_at          timestamptz not null default now(),
    chest_no            integer,
    initial             text,
    full_name           text,
    dob                 date,
    division            text,
    affiliation_kind    text,
    district            text,
    team                text,
    mobile              text,
    aadhaar_masked      text,
    declared_weight_kg  numeric(5,2),
    age_categories      text[],
    youth_hand          text,
    senior_hand         text,
    photo_url           text,
    photo_bytes         integer,
    submitted_by        text default 'self',
    is_para             boolean not null default false,
    para_class          text,
    para_posture        text,
    gender              text,
    nonpara_classes     text[],
    nonpara_hand        text,
    para_codes          text[],
    para_hand           text,
    nonpara_hands       text[],
    public_token        text not null default encode(gen_random_bytes(8), 'hex'),
    aadhaar             text,
    checkin_status      text not null default 'not_arrived',
    channel             text not null default 'offline',
    lifecycle_status    text not null default 'active',
    discipline_status   text not null default 'clear',
    weight_overrides    jsonb not null default '[]'::jsonb
);

-- payments --------------------------------------------------------------------
create table if not exists public.payments (
    id              uuid not null default gen_random_uuid(),
    registration_id uuid not null,
    amount_inr      integer not null,
    method          text not null default 'manual_upi',
    utr             text,
    proof_url       text,
    status          text not null default 'pending',
    verified_by     uuid,
    verified_at     timestamptz,
    notes           text,
    created_at      timestamptz default now()
);

-- payment_collections ---------------------------------------------------------
create table if not exists public.payment_collections (
    id               uuid not null default gen_random_uuid(),
    payment_id       uuid not null,
    amount_inr       integer not null,
    method           text not null,
    reference        text,
    collected_by     uuid,
    collected_at     timestamptz not null default now(),
    reversed_at      timestamptz,
    reversed_by      uuid,
    reversal_reason  text,
    payer_label      text
);

-- payment_proofs --------------------------------------------------------------
create table if not exists public.payment_proofs (
    id          uuid not null default gen_random_uuid(),
    payment_id  uuid not null,
    utr         text not null,
    proof_url   text not null,
    created_at  timestamptz not null default now(),
    deleted_at  timestamptz
);

-- weigh_ins -------------------------------------------------------------------
create table if not exists public.weigh_ins (
    id              uuid not null default gen_random_uuid(),
    registration_id uuid not null,
    measured_kg     numeric(5,2) not null,
    live_photo_url  text,
    scale_photo_url text,
    weighed_by      uuid,
    weighed_at      timestamptz default now()
);

-- venue_tables ----------------------------------------------------------------
create table if not exists public.venue_tables (
    id        uuid not null default gen_random_uuid(),
    event_id  uuid not null,
    number    integer not null,
    label     text
);

-- categories ------------------------------------------------------------------
create table if not exists public.categories (
    id                 uuid not null default gen_random_uuid(),
    event_id           uuid not null,
    weight_class_code  text not null,
    hand               text not null default 'right',
    division           text not null,
    display_name       text not null,
    status             text not null default 'pending',
    bracket_format     text not null default 'double_elim',
    created_at         timestamptz not null default now(),
    table_no           smallint
);

-- hubs ------------------------------------------------------------------------
create table if not exists public.hubs (
    id            uuid not null default gen_random_uuid(),
    event_id      uuid not null,
    table_id      uuid,
    code          text not null,
    display_name  text not null,
    status        text not null default 'offline',
    public_key    bytea,
    last_seen_at  timestamptz,
    created_at    timestamptz not null default now()
);

-- hub_devices -----------------------------------------------------------------
create table if not exists public.hub_devices (
    id            uuid not null default gen_random_uuid(),
    hub_id        uuid not null,
    kind          text not null,
    label         text,
    public_key    bytea,
    last_seen_at  timestamptz,
    created_at    timestamptz not null default now()
);

-- category_assignments --------------------------------------------------------
create table if not exists public.category_assignments (
    id          uuid not null default gen_random_uuid(),
    category_id uuid not null,
    hub_id      uuid not null,
    started_at  timestamptz not null default now(),
    ended_at    timestamptz,
    reason      text
);

-- chest_blocks ----------------------------------------------------------------
create table if not exists public.chest_blocks (
    event_id    uuid not null,
    group_key   text not null,
    base        integer not null,
    created_at  timestamptz not null default now()
);

-- entries ---------------------------------------------------------------------
create table if not exists public.entries (
    id              uuid not null default gen_random_uuid(),
    registration_id uuid not null,
    division        text not null,
    age_band        text not null,
    weight_class    text not null,
    hand            text not null,
    category_code   text not null,
    seed            integer
);

-- fixtures --------------------------------------------------------------------
create table if not exists public.fixtures (
    id                       uuid not null default gen_random_uuid(),
    event_id                 uuid not null,
    category_code            text not null,
    round_no                 integer not null,
    match_no                 integer not null,
    entry_a_id               uuid,
    entry_b_id               uuid,
    next_match_id            uuid,
    bracket_side             text not null default 'W',
    next_round_no            integer,
    next_match_no            integer,
    next_bracket_side        text,
    loser_next_round_no      integer,
    loser_next_match_no      integer,
    loser_next_bracket_side  text,
    best_of                  smallint not null default 1,
    winner_entry_id          uuid,
    created_at               timestamptz not null default now(),
    status                   text not null default 'scheduled',
    score_a                  smallint not null default 0,
    score_b                  smallint not null default 0,
    method                   text,
    mat_no                   smallint,
    started_at               timestamptz,
    completed_at             timestamptz,
    updated_by               uuid,
    updated_at               timestamptz not null default now()
);

-- audit_log -------------------------------------------------------------------
create table if not exists public.audit_log (
    id            bigint not null default nextval('public.audit_log_id_seq'::regclass),
    event_id      uuid,
    actor_id      uuid,
    actor_label   text,
    action        text not null,
    target_table  text,
    target_id     text,
    payload       jsonb,
    client_ip     text,
    created_at    timestamptz default now()
);
alter sequence public.audit_log_id_seq owned by public.audit_log.id;

-- event_log -------------------------------------------------------------------
create table if not exists public.event_log (
    id          uuid not null,
    event_id    uuid,
    category_id uuid,
    hub_id      uuid,
    device_id   uuid,
    actor_id    uuid,
    topic       text not null,
    payload     jsonb not null,
    client_ts   timestamptz not null,
    server_ts   timestamptz not null default now(),
    prev_hash   bytea,
    hash        bytea not null,
    signature   bytea
);

-- =============================================================================
-- PRIMARY KEYS
-- =============================================================================
alter table public.profiles             add constraint profiles_pkey             primary key (id);
alter table public.organizations        add constraint organizations_pkey        primary key (id);
alter table public.rule_profiles        add constraint rule_profiles_pkey        primary key (id);
alter table public.events               add constraint events_pkey               primary key (id);
alter table public.athletes             add constraint athletes_pkey             primary key (id);
alter table public.registrations        add constraint registrations_pkey        primary key (id);
alter table public.payments             add constraint payments_pkey             primary key (id);
alter table public.payment_collections  add constraint payment_collections_pkey  primary key (id);
alter table public.payment_proofs       add constraint payment_proofs_pkey       primary key (id);
alter table public.weigh_ins            add constraint weigh_ins_pkey            primary key (id);
alter table public.venue_tables         add constraint venue_tables_pkey         primary key (id);
alter table public.categories           add constraint categories_pkey           primary key (id);
alter table public.hubs                 add constraint hubs_pkey                 primary key (id);
alter table public.hub_devices          add constraint hub_devices_pkey          primary key (id);
alter table public.category_assignments add constraint category_assignments_pkey primary key (id);
alter table public.chest_blocks         add constraint chest_blocks_pkey         primary key (event_id, base);
alter table public.entries              add constraint entries_pkey              primary key (id);
alter table public.fixtures             add constraint fixtures_pkey             primary key (id);
alter table public.audit_log            add constraint audit_log_pkey            primary key (id);
alter table public.event_log            add constraint event_log_pkey            primary key (id);

-- =============================================================================
-- UNIQUE CONSTRAINTS
-- =============================================================================
alter table public.organizations add constraint organizations_slug_key unique (slug);
alter table public.rule_profiles add constraint rule_profiles_code_key unique (code);
alter table public.events        add constraint events_slug_key        unique (slug);
alter table public.categories    add constraint categories_event_id_weight_class_code_hand_key unique (event_id, weight_class_code, hand);
alter table public.hubs          add constraint hubs_event_id_code_key unique (event_id, code);
alter table public.venue_tables  add constraint venue_tables_event_id_number_key unique (event_id, number);
alter table public.entries       add constraint entries_registration_id_division_age_band_weight_class_hand_key unique (registration_id, division, age_band, weight_class, hand);
alter table public.fixtures      add constraint fixtures_event_cat_side_round_match_key unique (event_id, category_code, bracket_side, round_no, match_no);
alter table public.registrations add constraint registrations_event_id_athlete_id_weight_class_code_hand_key unique (event_id, athlete_id, weight_class_code, hand);

-- =============================================================================
-- CHECK CONSTRAINTS
-- =============================================================================
alter table public.organizations add constraint organizations_kind_check check (kind = any (array['federation'::text, 'organiser'::text, 'league'::text, 'club'::text]));
alter table public.profiles      add constraint profiles_role_check      check (role = any (array['athlete'::text, 'operator'::text, 'super_admin'::text]));

alter table public.rule_profiles add constraint rule_profiles_bracket_default_check
    check (bracket_default = any (array['double_elim'::text, 'single_elim'::text, 'round_robin'::text, 'top8_no_loser'::text, 'six_round_supermatch'::text]));

alter table public.events add constraint events_bracket_format_check         check (bracket_format = any (array['double_elim'::text, 'single_elim'::text, 'round_robin'::text]));
alter table public.events add constraint events_entry_fee_offline_inr_check  check (entry_fee_offline_inr is null or entry_fee_offline_inr >= 0);
alter table public.events add constraint events_entry_fee_para_inr_check     check (entry_fee_para_inr    is null or entry_fee_para_inr    >= 0);
alter table public.events add constraint events_hand_check                   check (hand = any (array['right'::text, 'left'::text, 'both'::text]));
alter table public.events add constraint events_id_card_event_title_size_chk check (id_card_event_title_size is null or (id_card_event_title_size between 6 and 16));
alter table public.events add constraint events_id_card_org_name_size_chk    check (id_card_org_name_size    is null or (id_card_org_name_size    between 5 and 14));
alter table public.events add constraint events_payment_mode_check           check (payment_mode = any (array['online_upi'::text, 'offline'::text, 'hybrid'::text]));
alter table public.events add constraint events_payment_provider_check       check (payment_provider = any (array['manual_upi'::text, 'razorpay'::text, 'none'::text]));
alter table public.events add constraint events_poster_kind_check            check (poster_kind = any (array['image'::text, 'pdf'::text]));
alter table public.events add constraint events_status_check                 check (status = any (array['draft'::text, 'open'::text, 'live'::text, 'completed'::text, 'archived'::text]));

alter table public.athletes add constraint athletes_aadhaar_format     check (aadhaar is null or aadhaar ~ '^[0-9]{12}$');
alter table public.athletes add constraint athletes_gender_check       check (gender = any (array['M'::text, 'F'::text, 'O'::text]));
alter table public.athletes add constraint athletes_para_posture_check check (para_posture = any (array['Standing'::text, 'Seated'::text]));

alter table public.registrations add constraint registrations_aadhaar_format          check (aadhaar is null or aadhaar ~ '^[0-9]{12}$');
alter table public.registrations add constraint registrations_affiliation_kind_check  check (affiliation_kind = any (array['District'::text, 'Team'::text]));
alter table public.registrations add constraint registrations_channel_check           check (channel = any (array['online'::text, 'offline'::text]));
alter table public.registrations add constraint registrations_checkin_status_check    check (checkin_status = any (array['not_arrived'::text, 'weighed_in'::text, 'no_show'::text]));
alter table public.registrations add constraint registrations_discipline_status_check check (discipline_status = any (array['clear'::text, 'disqualified'::text]));
alter table public.registrations add constraint registrations_division_check          check (division = any (array['Men'::text, 'Women'::text, 'Para Men'::text, 'Para Women'::text]));
alter table public.registrations add constraint registrations_gender_check            check (gender = any (array['M'::text, 'F'::text, 'O'::text]));
alter table public.registrations add constraint registrations_lifecycle_status_check  check (lifecycle_status = any (array['active'::text, 'withdrawn'::text]));
alter table public.registrations add constraint registrations_nonpara_hand_check      check (nonpara_hand = any (array['R'::text, 'L'::text, 'B'::text]));
alter table public.registrations add constraint registrations_para_hand_check         check (para_hand = any (array['R'::text, 'L'::text, 'B'::text]));
alter table public.registrations add constraint registrations_para_posture_check      check (para_posture = any (array['Standing'::text, 'Seated'::text]));
alter table public.registrations add constraint registrations_senior_hand_check       check (senior_hand = any (array['R'::text, 'L'::text, 'B'::text]));
alter table public.registrations add constraint registrations_status_check            check (status = any (array['pending'::text, 'paid'::text, 'weighed_in'::text, 'withdrawn'::text, 'disqualified'::text]));
alter table public.registrations add constraint registrations_youth_hand_check        check (youth_hand = any (array['R'::text, 'L'::text, 'B'::text]));

alter table public.payments add constraint payments_method_check check (method = any (array['manual_upi'::text, 'razorpay'::text, 'cash'::text, 'waiver'::text]));
alter table public.payments add constraint payments_status_check check (status = any (array['pending'::text, 'submitted'::text, 'verified'::text, 'rejected'::text]));

alter table public.payment_collections add constraint payment_collections_amount_inr_check check (amount_inr >= 0);
alter table public.payment_collections add constraint payment_collections_method_check     check (method = any (array['manual_upi'::text, 'razorpay'::text, 'cash'::text, 'waiver'::text]));

alter table public.categories add constraint categories_hand_check     check (hand = any (array['right'::text, 'left'::text]));
alter table public.categories add constraint categories_status_check   check (status = any (array['pending'::text, 'calling'::text, 'live'::text, 'paused'::text, 'completed'::text]));
alter table public.categories add constraint categories_table_no_check check (table_no is null or table_no > 0);

alter table public.hubs        add constraint hubs_status_check      check (status = any (array['offline'::text, 'online'::text, 'degraded'::text, 'retired'::text]));
alter table public.hub_devices add constraint hub_devices_kind_check check (kind   = any (array['controller'::text, 'mc_tablet'::text, 'sideref_tablet'::text, 'checkin_tablet'::text, 'camera'::text, 'led_display'::text]));

alter table public.chest_blocks add constraint chest_blocks_base_check check (base >= 1000 and (base % 100) = 0);

alter table public.entries  add constraint entries_hand_check                       check (hand = any (array['R'::text, 'L'::text]));
alter table public.fixtures add constraint fixtures_best_of_check                   check (best_of = any (array[1, 3, 5]));
alter table public.fixtures add constraint fixtures_bracket_side_check              check (bracket_side = any (array['W'::text, 'L'::text, 'GF'::text]));
alter table public.fixtures add constraint fixtures_loser_next_bracket_side_check   check (loser_next_bracket_side is null or (loser_next_bracket_side = any (array['W'::text, 'L'::text, 'GF'::text])));
alter table public.fixtures add constraint fixtures_method_check                    check (method is null or (method = any (array['points'::text, 'pin'::text, 'disqualification'::text, 'walkover'::text, 'forfeit'::text, 'injury'::text])));
alter table public.fixtures add constraint fixtures_next_bracket_side_check         check (next_bracket_side is null or (next_bracket_side = any (array['W'::text, 'L'::text, 'GF'::text])));
alter table public.fixtures add constraint fixtures_status_check                    check (status = any (array['scheduled'::text, 'in_progress'::text, 'completed'::text, 'void'::text]));

-- =============================================================================
-- FOREIGN KEYS (after all tables exist; order is irrelevant)
-- =============================================================================
alter table public.profiles
    add constraint profiles_id_fkey         foreign key (id)         references auth.users(id) on delete cascade,
    add constraint profiles_invited_by_fkey foreign key (invited_by) references public.profiles(id);

alter table public.events
    add constraint events_created_by_fkey      foreign key (created_by)      references public.profiles(id)      on delete set null,
    add constraint events_organization_id_fkey foreign key (organization_id) references public.organizations(id) on delete cascade,
    add constraint events_rule_profile_id_fkey foreign key (rule_profile_id) references public.rule_profiles(id);

alter table public.athletes
    add constraint athletes_id_fkey foreign key (id) references public.profiles(id) on delete cascade;

alter table public.registrations
    add constraint registrations_athlete_id_fkey foreign key (athlete_id) references public.athletes(id) on delete set null,
    add constraint registrations_event_id_fkey   foreign key (event_id)   references public.events(id)   on delete cascade;

alter table public.payments
    add constraint payments_registration_id_fkey foreign key (registration_id) references public.registrations(id) on delete cascade,
    add constraint payments_verified_by_fkey     foreign key (verified_by)     references public.profiles(id)      on delete set null;

alter table public.payment_collections
    add constraint payment_collections_collected_by_fkey foreign key (collected_by) references public.profiles(id) on delete set null,
    add constraint payment_collections_payment_id_fkey   foreign key (payment_id)   references public.payments(id) on delete cascade,
    add constraint payment_collections_reversed_by_fkey  foreign key (reversed_by)  references public.profiles(id) on delete set null;

alter table public.payment_proofs
    add constraint payment_proofs_payment_id_fkey foreign key (payment_id) references public.payments(id) on delete cascade;

alter table public.weigh_ins
    add constraint weigh_ins_registration_id_fkey foreign key (registration_id) references public.registrations(id) on delete cascade,
    add constraint weigh_ins_weighed_by_fkey      foreign key (weighed_by)      references public.profiles(id)      on delete set null;

alter table public.venue_tables
    add constraint venue_tables_event_id_fkey foreign key (event_id) references public.events(id) on delete cascade;

alter table public.categories
    add constraint categories_event_id_fkey foreign key (event_id) references public.events(id) on delete cascade;

alter table public.hubs
    add constraint hubs_event_id_fkey foreign key (event_id) references public.events(id)        on delete cascade,
    add constraint hubs_table_id_fkey foreign key (table_id) references public.venue_tables(id) on delete set null;

alter table public.hub_devices
    add constraint hub_devices_hub_id_fkey foreign key (hub_id) references public.hubs(id) on delete cascade;

alter table public.category_assignments
    add constraint category_assignments_category_id_fkey foreign key (category_id) references public.categories(id) on delete cascade,
