alter table public.fixtures
    add constraint fixtures_entry_a_id_fkey      foreign key (entry_a_id)      references public.entries(id)  on delete set null,
    add constraint fixtures_entry_b_id_fkey      foreign key (entry_b_id)      references public.entries(id)  on delete set null,
